      options: [{ id: `A`, text: `f(x) = −6·2<sup>x</sup>` }, { id: `B`, text: `f(x) = −6·2<sup>x</sup> − 2` }, { id: `C`, text: `f(x) = −6·2<sup>x</sup> − 4` }, { id: `D`, text: `f(x) = −6·2<sup>x</sup> − 6` }],
